function LNewbieMap:OnDestroy()
    local manager = self:GetManager()
    if manager and manager:IsStoryStop() then
        gLGpManager:DestroyGp(LGamePlayType.NEWBIE)
    end

    LMapBase.OnDestroy(self)
end

function LNewbieMap:OnCreate()
    LMapBase.OnCreate(self)
end

function LNewbieMap:OnResetMap()
    self:InitCurStoryData()
end

function LNewbieMap:OnExitMap()
    local manager = self:GetManager()
    if manager then
        manager:OnExitMap()
    end
end

function LNewbieMap:IsCheckClear()
    return true
end

