function LNewbieMap:InitCurStoryData()
    local mapName = "MapNewbie"
    self:SetMapName(mapName)

end

function LNewbieMap:OnEnterMap()
	self:InitPostProcess()
    gLGpManager:FindNewbieGp():OnMapLoaded(self._mapTrans, self._mapCameraCom.gameObject)
end

function LNewbieMap:InitPostProcess()
	-- 这里先初始化一下post
	gLGamePostProcess:ShowSceneGray(0.2, 0, function()
		gLGamePostProcess:HideSceneGray(0)
	end)
end

-----------------------------------------------------------------
function LNewbieMap:GetManager()
    if gLGpManager and gLGpManager:IsGpInit(LGamePlayType.NEWBIE) then
        local impl = gLGpManager:FindNewbieGp()
        return impl
    end
end
